const t = $('Trigger').first().json;
// Programmatically enforce subscription_renewal when flag is set
const purpose = t.is_subscription_renewal === true
  ? 'subscription_renewal'
  : (t.purpose || 'invoice');
const total = parseFloat(t.total || t.amount || 0);
// Deposit = 20% of invoice total; all other purposes = full amount
const chargeAmount = purpose === 'deposit'
  ? parseFloat((total * 0.2).toFixed(3))
  : total;
// Allow custom expiry override (e.g. 72h for subscription renewals from WF-25)
const expiresAt = t.custom_expires_at || new Date(Date.now() + 30 * 60 * 1000).toISOString();
return [{ json: { ...t, purpose, charge_amount: chargeAmount, expires_at: expiresAt } }];

const t   = $('Trigger').first().json;
const pd  = $('Prep Payment Data').first().json;
const res = $json;

const sessionId = (res.data && res.data.session_id) ? res.data.session_id : (res.session_id || null);
const baseUrl   = $vars.THAWANI_BASE_URL || 'https://uatcheckout.thawani.om';
const checkoutUrl = sessionId
  ? (baseUrl + '/pay/' + sessionId + '?key=' + ($vars.THAWANI_PUBLIC_KEY || ''))
  : null;

return [{ json: {
  ...t,
  thawani_session_id: sessionId,
  payment_url:        checkoutUrl,
  purpose:            pd.purpose,
  charge_amount:      pd.charge_amount,
  expires_at:         pd.expires_at
} }];

const t       = $('Trigger').first().json;
const urlData = $('Extract Payment URL').first().json;
const link    = $('Save Payment Link').first().json;
return [{ json: {
  ...t,
  payment_link_id:    link.id,
  payment_url:        urlData.payment_url,
  thawani_session_id: urlData.thawani_session_id,
  purpose:            urlData.purpose,
  charge_amount:      urlData.charge_amount
} }];
